import { Component } from '@angular/core';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent {
}
<div class="row container home">
  <h1>Welcome to invoice tracker system</h1>

  <p>You are required to sign in/sign up to access the system</p>

  <p>Be aware some parts of the system requires admin access</p>
</div>
